const items = $input.all();

return items.map((item) => {
  let text = item.json.output || "";

  // Definimos ambos triggers (Venta y Reunión)
  const triggerVenta = "perfecto, entre los proximos 2 dias habiles se contactara un diseñador con vos";
  const triggerReunion = "genial, te esperamos en la reunion";
  const tag = "[STATUS: CLOSED]";

  // 1. Detección de cierre (evalúa si tiene la frase de venta, la de reunión, o directamente el tag)
  item.json.should_close = text.toLowerCase().includes(triggerVenta.toLowerCase()) || 
                           text.toLowerCase().includes(triggerReunion.toLowerCase()) ||
                           text.includes(tag);

  // 2. Limpieza INTELIGENTE
  let cleanOutput = text
    .replace(tag, "") // Borramos el tag técnico
    .replace(/\n{3,}/g, '\n\n') // Si hay 3 o más saltos de línea seguidos, deja solo 2.
    .trim(); // Quita espacios vacíos al inicio y final

  item.json.output = cleanOutput;

  return item;
});

for (const item of $input.all()) {
  // 1. Viajamos al nodo 'Aggregate' para traer el array original separado por mensajes
  const arrayMensajes = $('Aggregate').first().json.message;

  if (arrayMensajes && Array.isArray(arrayMensajes)) {
    // 2. Filtramos mágicamente: guardamos todo EXCEPTO lo que contenga la palabra "[IMAGEN]"
    const soloTextoUsuario = arrayMensajes.filter(mensaje => !mensaje.includes('[IMAGEN]'));

    // 3. Ahora sí, concatenamos pero solo los mensajes reales del cliente
    item.json.mensaje_limpio = soloTextoUsuario.join(" ").trim();
  } else {
    // Fallback de seguridad
    item.json.mensaje_limpio = $('Edit Fields5').first().json.Input; 
  }
}

return $input.all();

